  "sentences": [
    {
      "text": "今天天氣很熱，我心情不好。",
      "pinyin": "Jīntiān tiānqì hěn rè, wǒ xīnqíng bù hǎo.",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 re4, wo3 xin1qing2 bu4 hao3.",
      "translation_en": "The weather is very hot today, and I'm in a bad mood.",
      "translation_ko": "오늘 날씨가 매우 더워서 기분이 안 좋아요."
    },
    {
      "text": "昨天天氣很冷，可是我很開心。",
      "pinyin": "Zuótiān tiānqì hěn lěng, kěshì wǒ hěn kāixīn.",
      "pinyin_numeric": "zuo2tian1 tian1qi4 hen3 leng3, ke3shi4 wo3 hen3 kai1xin1.",
      "translation_en": "Yesterday the weather was very cold, but I was very happy.",
      "translation_ko": "어제 날씨가 매우 추웠지만 저는 매우 기뻤어요."
    },
    {
      "text": "晴天很舒服，我的心情也很好。",
      "pinyin": "Qíngtiān hěn shūfú, wǒ de xīnqíng yě hěn hǎo.",
      "pinyin_numeric": "qing2tian1 hen3 shu1fu2, wo3 de xin1qing2 ye3 hen3 hao3.",
      "translation_en": "Sunny weather is very comfortable, and my mood is also very good.",
      "translation_ko": "맑은 날씨가 매우 쾌적하고 제 기분도 아주 좋아요."
    },
    {
      "text": "陰天很悶熱，我沒有精神。",
      "pinyin": "Yīntiān hěn mēnrè, wǒ méiyǒu jīngshén.",
      "pinyin_numeric": "yin1tian1 hen3 men1re4, wo3 mei2you3 jing1shen2.",
      "translation_en": "Cloudy weather is very muggy, and I have no energy.",
      "translation_ko": "흐린 날씨가 매우 후덥지근해서 기운이 없어요."
    },
    {
      "text": "下雨天很涼快，我的心情很放鬆。",
      "pinyin": "Xiàyǔ tiān hěn liángkuài, wǒ de xīnqíng hěn fàngsōng.",
      "pinyin_numeric": "xia4yu3 tian1 hen3 liang2kuai4, wo3 de xin1qing2 hen3 fang4song1.",
      "translation_en": "Rainy weather is very cool, and my mood is very relaxed.",
      "translation_ko": "비 오는 날씨가 매우 시원해서 제 기분이 매우 편안해요."
    },
    {
      "text": "颱風天風很大，我很緊張。",
      "pinyin": "Táifēng tiān fēng hěn dà, wǒ hěn jǐnzhāng.",
      "pinyin_numeric": "tai2feng1 tian1 feng1 hen3 da4, wo3 hen3 jin3zhang1.",
      "translation_en": "Typhoon weather has very strong winds, and I am very nervous.",
      "translation_ko": "태풍 날씨에 바람이 매우 세서 저는 매우 긴장돼요."
    },
    {
      "text": "今天溫度三十度，天氣很熱，我壓力很大。",
      "pinyin": "Jīntiān wēndù sānshí dù, tiānqì hěn rè, wǒ yālì hěn dà.",
      "pinyin_numeric": "jin1tian1 wen1du4 san1shi2 du4, tian1qi4 hen3 re4, wo3 ya1li4 hen3 da4.",
      "translation_en": "Today the temperature is 30 degrees, the weather is very hot, and I am very stressed.",
      "translation_ko": "오늘 기온이 30도이고 날씨가 매우 더워서 스트레스가 많아요."
    },
    {
      "text": "多雲天氣很舒服，我心情很好。",
      "pinyin": "Duōyún tiānqì hěn shūfú, wǒ xīnqíng hěn hǎo.",
      "pinyin_numeric": "duo1yun2 tian1qi4 hen3 shu1fu2, wo3 xin1qing2 hen3 hao3.",
      "translation_en": "Cloudy weather is very comfortable, and my mood is very good.",
      "translation_ko": "구름 낀 날씨가 매우 쾌적해서 기분이 아주 좋아요."
    },
    {
      "text": "昨天很冷，我穿外套，可是心情很開心。",
      "pinyin": "Zuótiān hěn lěng, wǒ chuān wàitào, kěshì xīnqíng hěn kāixīn.",
